// Declaração e acesso
int[] arr = new int[5];
arr[0] = 10;
arr[1] = 20;

// Inserção com shift (manual)
void InsertAt(int[] arr, ref int size, int index, int value) {
    for (int i = size; i > index; i--)
        arr[i] = arr[i - 1];  // desloca para direita
    arr[index] = value;
    size++;
}

