codeSnippets.javascript:
// Array de tamanho fixo
const arr = new Array(5).fill(0);
arr[0] = 10;

// Inserção com shift
function insertAt(arr, size, index, value) {
    for (let i = size; i > index; i--)
        arr[i] = arr[i - 1];  // desloca para direita
    arr[index] = value;
    return size + 1;
}
